<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function wlError(m){$('.isi_warning_delete').text(m||'Work Location gagal diproses.');$('.error_data_delete').fadeIn();}
function wlFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),location_type:$('#filter_location_type').val(),status:$('#filter_status').val(),city:$('#filter_city').val(),keyword:$('#filter_keyword').val()};}
function wlSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change')}
function wlReset(title){$('#form_work_location')[0].reset();$('#wl_id').val('');$('#company_structure_id,#plant_id,#storage_location_id,#cost_center_code,#profit_center_code').val(null).trigger('change');$('#location_type,#work_location_category,#status,#working_calendar_code,#default_shift_code,#timezone,#attendance_required').val('').trigger('change');$('#location_type').val('PLANT').trigger('change');$('#work_location_category').val('PRIMARY').trigger('change');$('#status').val('DRAFT').trigger('change');$('#timezone').val('Asia/Jakarta').trigger('change');$('#attendance_required').val('Y').trigger('change');$('#country').val('ID');$('#valid_from').val('<?=$defaultFrom;?>');$('#valid_to').val('<?=$defaultTo;?>');$('#capacity_headcount').val('0');$('#modal_work_location .modal-title').text(title||'Create Work Location')}
function wlAjax(s,a,p){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:$('#modal_work_location'),ajax:{url:'<?=base_admin();?>modul/work_location/work_location_action.php?act='+a,type:'POST',dataType:'json',delay:250,data:function(x){return{term:x.term||'',plant_id:$('#plant_id').val()||''}},processResults:function(d){return{results:d.results||[]}}}})}
$(function(){if($.fn.datepicker){$('.wl-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true})}if($.fn.select2){$('#filter_location_type,#filter_status,#location_type,#work_location_category,#status,#working_calendar_code,#default_shift_code,#timezone,#attendance_required').select2({width:'100%',allowClear:true});wlAjax('#company_structure_id','company_structure_search','Pilih org unit...');wlAjax('#plant_id','plant_search','Pilih plant...');wlAjax('#storage_location_id','storage_location_search','Pilih storage location...');wlAjax('#cost_center_code','cost_center_search','Pilih cost center...');wlAjax('#profit_center_code','profit_center_search','Pilih profit center...')}
var dt=$('#dtb_work_location').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'90px',targets:1}],ajax:{url:'<?=base_admin();?>modul/work_location/work_location_data.php',type:'post',data:function(d){$.extend(d,wlFilters())},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_plant').text(k.plant||0);$('#kpi_warehouse').text(k.warehouse||0);$('#kpi_capacity').text(k.capacity||0);return j.data||[]},error:function(x){console.log(x.responseText);wlError('Data Work Location gagal dimuat.')}}});
$('#btn_open_wl').click(function(){wlReset('Create Work Location');$('#modal_work_location').modal({backdrop:'static',keyboard:false})});$('#btn_filter_wl').click(function(){dt.draw()});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw()});$('#btn_reset_wl').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_location_type,#filter_status').val(null).trigger('change');$('#filter_city,#filter_keyword').val('');dt.draw()});$('#btn_export_wl').click(function(){window.location='<?=base_admin();?>modul/work_location/work_location_action.php?act=export&'+$.param(wlFilters())});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide()});$('#location_code,#country').on('keyup change',function(){this.value=this.value.toUpperCase()});$('#plant_id').on('change',function(){$('#storage_location_id').val(null).trigger('change')});
$('#form_work_location').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/work_location/work_location_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Location');if(r.status==='good'){$('#modal_work_location').modal('hide');dt.draw(false);Swal.fire('Saved','Work Location berhasil disimpan.','success')}else wlError(r.error_message)},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Location');wlError(x.responseText)})});
$(document).on('click','.btn-wl-detail',function(){$.post('<?=base_admin();?>modul/work_location/work_location_action.php?act=detail',{id:$(this).data('id')},function(h){$('#wl_detail_body').html(h);$('#modal_wl_detail').modal('show')})});
$(document).on('click','.btn-wl-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/work_location/work_location_action.php?act=get',{id:id},function(r){if(r.status!=='good'){wlError(r.error_message);return}wlReset('Edit Work Location');var h=r.data||{};Object.keys(h).forEach(function(k){var e=$('#'+k);if(e.length&&!['company_structure_id','plant_id','storage_location_id','cost_center_code','profit_center_code'].includes(k))e.val(h[k])});$('#wl_id').val(h.id);wlSet('#company_structure_id',h.company_structure_id,h.company_structure_text);wlSet('#plant_id',h.plant_id,h.plant_text);wlSet('#storage_location_id',h.storage_location_id,h.storage_location_text);wlSet('#cost_center_code',h.cost_center_code,h.cost_center_text);wlSet('#profit_center_code',h.profit_center_code,h.profit_center_text);$('#location_type,#work_location_category,#status,#working_calendar_code,#default_shift_code,#timezone,#attendance_required').trigger('change');$('#modal_work_location').modal({backdrop:'static',keyboard:false})},'json')});
$(document).on('click','.btn-wl-delete',function(){var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/work_location/work_location_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success')}else wlError(r.error_message)},'json')})})});
</script>
